import Link from "next/link";
import { createClient } from "@/app/lib/supabase/server";
import { formatDate, getNextAction } from "@/app/lib/show-workflow";
import { saveAkteAction } from "./saveAkteAction";

export default async function ShowAktePage({
  params,
}: {
  params: { id: string };
}) {
  const supabase = await createClient();

  const { data: show, error } = await supabase
    .from("shows")
    .select(`
      *,
      show_details (*),
      show_admin_notes (*),
      show_files (*)
    `)
    .eq("id", params.id)
    .single();

  if (error || !show) {
    return (
      <main className="p-8">
        <p className="text-red-600">Show nicht gefunden.</p>
      </main>
    );
  }

  const details = show.show_details ?? {};
  const admin = show.show_admin_notes ?? {};
  const nextAction = getNextAction(show);

  return (
    <main className="min-h-screen bg-neutral-50 p-6">
      <form action={saveAkteAction} className="mx-auto max-w-7xl space-y-6">
        <input type="hidden" name="show_id" value={show.id} />

        <header className="sticky top-0 z-20 rounded-3xl bg-white/95 p-5 shadow-sm ring-1 ring-neutral-200 backdrop-blur">
          <div className="flex flex-col gap-5 lg:flex-row lg:items-start lg:justify-between">
            <div>
              <Link
                href="/admin"
                className="text-sm font-medium text-neutral-500 hover:text-neutral-950"
              >
                ← Zurück zum Cockpit
              </Link>

              <h1 className="mt-3 text-3xl font-bold tracking-tight text-neutral-950">
                {show.venue}
              </h1>

              <p className="mt-1 text-neutral-600">
                {formatDate(show.show_date)} · {show.city} · {show.program}
              </p>
            </div>

            <div className="flex flex-wrap gap-2">
              <button className="rounded-2xl bg-neutral-950 px-5 py-3 text-sm font-semibold text-white">
                Akte speichern
              </button>

              {show.token && (
                <Link
                  href={`/show/${show.token}`}
                  className="rounded-2xl bg-neutral-100 px-5 py-3 text-sm font-semibold text-neutral-800"
                >
                  Portal öffnen
                </Link>
              )}

              <a
                href={`mailto:${details.contact_email ?? ""}`}
                className="rounded-2xl bg-neutral-100 px-5 py-3 text-sm font-semibold text-neutral-800"
              >
                Mail vorbereiten
              </a>
            </div>
          </div>

          <div className="mt-5 grid gap-3 md:grid-cols-4">
            <SummaryBox label="Status" value={admin.internal_status ?? "offen"} />
            <SummaryBox label="Abrechnung" value={admin.billing_status ?? "offen"} />
            <SummaryBox label="Nächster Schritt" value={nextAction} />
            <SummaryBox
              label="Markus"
              value={admin.markus_included ? "dabei" : "nicht dabei"}
            />
          </div>
        </header>

        <div className="grid gap-6 lg:grid-cols-[1fr_360px]">
          <section className="space-y-4">
            <AkteSection title="Veranstaltung">
              <Field name="artist" label="Artist" defaultValue={show.artist} />
              <Field name="program" label="Programm" defaultValue={show.program} />
              <Field name="show_date" label="Datum" type="date" defaultValue={show.show_date} />
              <Field name="weekday" label="Wochentag" defaultValue={show.weekday} />
              <Field name="venue" label="Venue" defaultValue={show.venue} />
              <Field name="city" label="Stadt" defaultValue={show.city} />
              <Field name="start_time" label="Beginn" type="time" defaultValue={show.start_time} />
              <Field name="entry_time" label="Einlass" type="time" defaultValue={show.entry_time} />
            </AkteSection>

            <AkteSection title="Kontakt">
              <Field name="contact_name" label="Ansprechpartner" defaultValue={details.contact_name} />
              <Field name="contact_email" label="E-Mail" defaultValue={details.contact_email} />
              <Field name="contact_phone" label="Telefon" defaultValue={details.contact_phone} />
              <Textarea name="venue_address" label="Adresse" defaultValue={details.venue_address} />
            </AkteSection>

            <AkteSection title="Ablauf">
              <Textarea name="schedule" label="Ablauf / Zeiten" defaultValue={details.schedule} />
            </AkteSection>

            <AkteSection title="Technik">
              <Textarea name="technik" label="Technik allgemein" defaultValue={details.technik} />
              <Field name="piano" label="Piano / Flügel / E-Piano" defaultValue={details.piano} />
              <Field name="sound" label="Ton" defaultValue={details.sound} />
              <Field name="light" label="Licht" defaultValue={details.light} />
            </AkteSection>

            <AkteSection title="Anreise & Unterkunft">
              <Textarea name="anreise" label="Anreise" defaultValue={details.anreise} />
              <Textarea name="unterkunft" label="Unterkunft" defaultValue={details.unterkunft} />
            </AkteSection>

            <AkteSection title="Vertrag / Tickets / Promotion">
              <Textarea name="vertrag" label="Vertrag" defaultValue={details.vertrag} />
              <Field name="tickets" label="Ticketlink" defaultValue={details.tickets} />
              <Textarea name="promotion" label="Promotion" defaultValue={details.promotion} />
            </AkteSection>

            <AkteSection title="Sonstiges">
              <Textarea name="general_notes" label="Allgemeine Notizen" defaultValue={details.general_notes} />
            </AkteSection>

            <AkteSection title="Dateien">
              {show.show_files?.length ? (
                <div className="space-y-2">
                  {show.show_files.map((file: any) => (
                    <Link
                      key={file.id}
                      href={`/api/admin/files/${file.id}`}
                      className="block rounded-2xl bg-neutral-50 px-4 py-3 text-sm font-medium text-neutral-800 hover:bg-neutral-100"
                    >
                      {file.file_name}
                    </Link>
                  ))}
                </div>
              ) : (
                <p className="text-sm text-neutral-500">Noch keine Dateien hochgeladen.</p>
              )}
            </AkteSection>
          </section>

          <aside className="space-y-4">
            <AkteSection title="Interne Steuerung">
              <Field
                name="internal_status"
                label="Interner Status"
                defaultValue={admin.internal_status}
              />

              <Field
                name="billing_status"
                label="Abrechnung"
                defaultValue={admin.billing_status}
              />

              <Field
                name="next_step"
                label="Nächster Schritt"
                defaultValue={admin.next_step}
              />

              <Field
                name="follow_up_date"
                label="Wiedervorlage"
                type="date"
                defaultValue={admin.follow_up_date}
              />

              <label className="flex items-center gap-3 rounded-2xl bg-neutral-50 p-4 text-sm font-medium text-neutral-800">
                <input
                  type="checkbox"
                  name="markus_included"
                  defaultChecked={admin.markus_included}
                  className="h-4 w-4"
                />
                Markus dabei
              </label>

              <Textarea
                name="internal_notes"
                label="Interne Notizen"
                defaultValue={admin.internal_notes}
              />
            </AkteSection>

            <AkteSection title="Checkliste">
              <ChecklistItem
                name="checklist_portal"
                label="Portal ausgefüllt"
                checked={admin.checklist?.portal}
              />
              <ChecklistItem
                name="checklist_technik"
                label="Technik geklärt"
                checked={admin.checklist?.technik}
              />
              <ChecklistItem
                name="checklist_vertrag"
                label="Vertrag geklärt"
                checked={admin.checklist?.vertrag}
              />
              <ChecklistItem
                name="checklist_promotion"
                label="Promotion geklärt"
                checked={admin.checklist?.promotion}
              />
              <ChecklistItem
                name="checklist_abrechnung"
                label="Abrechnung erledigt"
                checked={admin.checklist?.abrechnung}
              />
            </AkteSection>
          </aside>
        </div>
      </form>
    </main>
  );
}

function SummaryBox({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-2xl bg-neutral-50 p-4">
      <p className="text-xs font-semibold uppercase tracking-wide text-neutral-500">
        {label}
      </p>
      <p className="mt-1 text-sm font-semibold text-neutral-950">{value}</p>
    </div>
  );
}

function AkteSection({
  title,
  children,
}: {
  title: string;
  children: React.ReactNode;
}) {
  return (
    <section className="rounded-3xl bg-white p-5 shadow-sm ring-1 ring-neutral-200">
      <h2 className="mb-4 text-lg font-bold text-neutral-950">{title}</h2>
      <div className="grid gap-4 md:grid-cols-2">{children}</div>
    </section>
  );
}

function Field({
  name,
  label,
  defaultValue,
  type = "text",
}: {
  name: string;
  label: string;
  defaultValue?: string | null;
  type?: string;
}) {
  return (
    <label className="space-y-1 text-sm">
      <span className="font-medium text-neutral-700">{label}</span>
      <input
        name={name}
        type={type}
        defaultValue={defaultValue ?? ""}
        className="w-full rounded-2xl border border-neutral-200 px-4 py-3 outline-none focus:border-neutral-500"
      />
    </label>
  );
}

function Textarea({
  name,
  label,
  defaultValue,
}: {
  name: string;
  label: string;
  defaultValue?: string | null;
}) {
  return (
    <label className="space-y-1 text-sm md:col-span-2">
      <span className="font-medium text-neutral-700">{label}</span>
      <textarea
        name={name}
        defaultValue={defaultValue ?? ""}
        rows={4}
        className="w-full rounded-2xl border border-neutral-200 px-4 py-3 outline-none focus:border-neutral-500"
      />
    </label>
  );
}

function ChecklistItem({
  name,
  label,
  checked,
}: {
  name: string;
  label: string;
  checked?: boolean;
}) {
  return (
    <label className="flex items-center gap-3 rounded-2xl bg-neutral-50 p-4 text-sm font-medium text-neutral-800 md:col-span-2">
      <input type="checkbox" name={name} defaultChecked={checked} />
      {label}
    </label>
  );
}